import{_ as e,c as r,o as i,ag as o}from"./chunks/framework.Dj4VfQLU.js";const c=JSON.parse('{"title":"Admin Workflows","description":"","frontmatter":{"icon":"buildings"},"headers":[],"relativePath":"admin-workflows.md","filePath":"admin-workflows.md"}'),s={name:"admin-workflows.md"};function n(a,t,l,d,g,u){return i(),r("div",null,t[0]||(t[0]=[o('<h1 id="admin-workflows" tabindex="-1">Admin Workflows <a class="header-anchor" href="#admin-workflows" aria-label="Permalink to &quot;Admin Workflows&quot;">​</a></h1><p>BetterTaxi — like all <strong>BetterSuite products</strong> — is managed through a <strong>unified admin panel</strong>, giving you centralized control over every service you operate. Whether you&#39;re managing ride-hailing, parcel delivery, or later integrate food/shop delivery through BetterShop, it all happens from a single interface.</p><p><strong>🧭 Multi-Product Navigation</strong></p><ul><li>A <strong>product switcher dropdown</strong> in the <strong>top-left corner</strong> allows switching between active modules (e.g., BetterTaxi, BetterShop).</li><li>Shared resources like <strong>Customers</strong>, <strong>Regions</strong>, <strong>SMS Providers</strong>, and <strong>Payment Gateways</strong> are accessible in a <strong>All Panels</strong> section.</li><li>This design allows seamless scaling as you onboard more BetterSuite modules.</li></ul><hr><h4 id="🚦-dashboard-overview" tabindex="-1">🚦 Dashboard Overview <a class="header-anchor" href="#🚦-dashboard-overview" aria-label="Permalink to &quot;🚦 Dashboard Overview&quot;">​</a></h4><p>After logging in, the <strong>Dashboard</strong> provides a real-time overview of:</p><ul><li>Active orders, rides, or deliveries</li><li>Registered users and drivers</li><li>Revenue by product and region</li><li>Live service availability</li><li>Operational status of geofences, APIs, and notifications</li></ul><p>The dashboard is designed for <strong>daily visibility into platform health</strong>.</p><hr><h4 id="👤-user-management" tabindex="-1">👤 User Management <a class="header-anchor" href="#👤-user-management" aria-label="Permalink to &quot;👤 User Management&quot;">​</a></h4><p><strong>🚗 Drivers</strong></p><blockquote><p>Path: <strong>Drivers → All Drivers</strong></p></blockquote><ul><li>Require <strong>manual approval</strong> before activation <em>(auto-approved only for demo installs)</em></li><li>Admins can: <ul><li>View profiles and documents</li><li>Approve/reject new driver accounts</li><li>Assign drivers to services or regions</li><li>View ride history and earnings</li></ul></li><li>Admins <strong>cannot upload or alter driver documents manually</strong></li></ul><p><strong>👥 Customers</strong></p><blockquote><p>Path: <strong>Users → Customers</strong></p></blockquote><ul><li>Admins can: <ul><li>Create customers manually</li><li>View trip history</li><li>Ban/unban users from the platform</li></ul></li></ul><p><strong>🤝 Partners</strong></p><blockquote><p>Path: <strong>Partners → All Partners</strong></p></blockquote><ul><li>Used only if the <strong>Partnership Add-on</strong> is enabled</li><li>Configure revenue shares and view their associated transactions</li></ul><hr><h4 id="🚚-trip-delivery-management" tabindex="-1">🚚 Trip &amp; Delivery Management <a class="header-anchor" href="#🚚-trip-delivery-management" aria-label="Permalink to &quot;🚚 Trip &amp; Delivery Management&quot;">​</a></h4><p><strong>🕒 Ongoing Trips</strong></p><blockquote><p>Path: <strong>Trips → Ongoing</strong></p></blockquote><ul><li>Monitor live ride/delivery status</li><li>View real-time map location of drivers and customers</li><li><strong>Reassign drivers</strong> or cancel orders manually</li></ul><p><strong>📋 Past Trips</strong></p><blockquote><p>Path: <strong>Trips → History</strong></p></blockquote><ul><li>Access trip logs with search filters (by date, user, driver, region)</li><li>View pricing breakdown and trip path</li><li><strong>Fare cannot be edited</strong> post-trip</li></ul><p><strong>📝 Manual Order Creation</strong></p><p>Admins can manually <strong>create new orders or rides</strong> via the panel and <strong>assign available drivers</strong> directly.</p><hr><h4 id="💵-earnings-wallets-payouts" tabindex="-1">💵 Earnings, Wallets &amp; Payouts <a class="header-anchor" href="#💵-earnings-wallets-payouts" aria-label="Permalink to &quot;💵 Earnings, Wallets &amp; Payouts&quot;">​</a></h4><blockquote><p>Path: <strong>Payout → Driver</strong></p></blockquote><p><strong>💰 Wallet System</strong></p><ul><li>All users (customer, driver, admin, partner) have a dedicated <strong>wallet</strong></li><li>Used for: <ul><li>Incentives</li><li>Promo credits</li><li>Cancellation refunds</li><li>Settlements and commissions</li></ul></li></ul><p><strong>💳 Driver Payouts</strong></p><ul><li>Two supported models: <ol><li><strong>Stripe Connect</strong>: Automates payouts on scheduled intervals</li><li><strong>Manual Payouts</strong>: Export payout list as CSV for external processing</li></ol></li><li>Admins can view balance and payout logs for each driver</li></ul><p><strong>📈 Platform Revenue</strong></p><ul><li>Track commissions, service earnings, and cost breakdowns</li><li>Filter by region, service type, or date</li></ul><hr><h4 id="📢-communication-tools" tabindex="-1">📢 Communication Tools <a class="header-anchor" href="#📢-communication-tools" aria-label="Permalink to &quot;📢 Communication Tools&quot;">​</a></h4><p><strong>📣 Announcements</strong></p><blockquote><p>Path: <strong>Marketing → Announcements</strong></p></blockquote><ul><li>Create in-app announcements shown in the <strong>Announcements tab</strong> in mobile apps</li><li>Target by region, user role, or app version</li><li>Good for long-lasting messages (e.g., price changes, holidays)</li></ul><p><strong>🔔 Push Notifications</strong></p><ul><li>For <strong>custom, one-time alerts</strong>, use the Firebase Console directly</li><li>Push is used for: <ul><li>Trip status changes</li><li>Promotions</li><li>Transaction confirmations</li></ul></li></ul><hr><h4 id="📡-system-settings-integrations" tabindex="-1">📡 System Settings &amp; Integrations <a class="header-anchor" href="#📡-system-settings-integrations" aria-label="Permalink to &quot;📡 System Settings &amp; Integrations&quot;">​</a></h4><p><strong>🔧 Settings Overview</strong></p><p>Configure your system-wide defaults:</p><table tabindex="0"><thead><tr><th>Section</th><th>Description</th></tr></thead><tbody><tr><td><strong>Regions</strong></td><td>Create geofenced operational zones</td></tr><tr><td><strong>SMS Providers</strong></td><td>Integrate with one of 8 available providers</td></tr><tr><td><strong>Payment Gateways</strong></td><td>Choose from 22 options</td></tr><tr><td><strong>API Keys</strong></td><td>Enter values for Maps, Firebase, etc.</td></tr><tr><td><strong>Roles &amp; Access</strong></td><td>Define admin roles and permission scopes</td></tr></tbody></table><hr><h4 id="🔐-admin-roles-permissions" tabindex="-1">🔐 Admin Roles &amp; Permissions <a class="header-anchor" href="#🔐-admin-roles-permissions" aria-label="Permalink to &quot;🔐 Admin Roles &amp; Permissions&quot;">​</a></h4><blockquote><p>Path: <strong>Management → Users</strong></p></blockquote><ul><li>You can define multiple <strong>admin roles</strong>: <ul><li>Read-only</li><li>Finance-only</li><li>App-specific access</li></ul></li><li>Assign these roles to restrict access to different parts of the panel</li><li>Useful for support teams, franchise operators, or finance departments</li></ul><hr><h4 id="📊-insights-logs" tabindex="-1">📊 Insights &amp; Logs <a class="header-anchor" href="#📊-insights-logs" aria-label="Permalink to &quot;📊 Insights &amp; Logs&quot;">​</a></h4><p><strong>📈 Usage Analytics</strong></p><blockquote><p>Path: <strong>Insights</strong></p></blockquote><ul><li>Built-in charts for: <ul><li>Ride volumes</li><li>Revenue trends</li><li>App usage metrics</li></ul></li><li>Data is filterable by service, region, and time</li></ul><hr><h4 id="🧙-admin-installation-wizard" tabindex="-1">🧙 Admin Installation Wizard <a class="header-anchor" href="#🧙-admin-installation-wizard" aria-label="Permalink to &quot;🧙 Admin Installation Wizard&quot;">​</a></h4><p>At first boot (or reset), the Admin Panel will guide you through setup:</p><ol><li>License activation</li><li>Branding (logo, name)</li><li>Region + currency + language setup</li><li>Firebase and API integrations</li><li>SMS/payment provider selection</li></ol><p>This wizard can be rerun when needed for major resets or migrations.</p><hr><h4 id="✅-admin-workflow-summary" tabindex="-1">✅ Admin Workflow Summary <a class="header-anchor" href="#✅-admin-workflow-summary" aria-label="Permalink to &quot;✅ Admin Workflow Summary&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Task</th><th>Action Path</th></tr></thead><tbody><tr><td>Approve Driver</td><td>Drivers → All Drivers</td></tr><tr><td>Ban User</td><td>Customers</td></tr><tr><td>Create Manual Order</td><td>Dispatcher</td></tr><tr><td>View Live Trip Status</td><td>Trips → Ongoing</td></tr><tr><td>Assign Driver Manually</td><td>Within Trip Detail</td></tr><tr><td>Add Service Pricing</td><td>Settings → Pricing</td></tr><tr><td>Configure Commission</td><td>Settings → Pricing → Commission</td></tr><tr><td>Configure Partner Share</td><td>Partners</td></tr><tr><td>Send In-App Announcement</td><td>Marketings → Announcements</td></tr><tr><td>View Analytics</td><td>Insights Tab of some pages</td></tr><tr><td>Export Payouts</td><td>Payouts → Drivers</td></tr><tr><td>Set Admin Roles</td><td>Management → Users</td></tr></tbody></table>',68)]))}const m=e(s,[["render",n]]);export{c as __pageData,m as default};
